define([ 'core/log', ], function(log) { 'use strict'; const hasCourseIndexContent = () => { return !!document.querySelector( '#courseindex .courseindex-section, #courseindex [data-for="section"]', ); }; const injectPrerender = () => { const cfg = (window.M && M.cfg && M.cfg.theme_understandtech) || {}; const html = cfg.courseindexhtml; if (!html || hasCourseIndexContent()) { return false; } const placeholder = document.getElementById('course-index-placeholder'); const content = document.getElementById('courseindex-content'); if (!placeholder && !content) { return false; } if (placeholder) { placeholder.outerHTML = html.trim(); } else { content.innerHTML = html.trim(); } log.debug('theme_understandtech/courseindex_prerender: injected server HTML'); return hasCourseIndexContent(); }; return { init: function() { const run = () => { injectPrerender(); }; if (document.readyState === 'loading') { document.addEventListener('DOMContentLoaded', run); } else { run(); } }, }; });